#include<bits/stdc++.h>
using namespace std;
struct node
{
    int val,lson,rson;
}a[1000010];
int dis[1000010],fa[1000010],root[1000010];
bool del[1000010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
int merge(int x,int y)
{
    if(x==0||y==0)
    {
        return x+y;
    }
    if(a[x].val>a[y].val||(a[x].val==a[y].val&&x>y))
    {
        swap(x,y);
    }
    a[x].rson=merge(a[x].rson,y);
    if(dis[a[x].lson]<dis[a[x].rson])
    {
        swap(a[x].lson,a[x].rson);
    }
    dis[x]=dis[a[x].rson]+1;
    return x;
}
int main()
{
    int n,m;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i].val);
        fa[i]=root[i]=i;
    }
    scanf("%d",&m);
    while(m--)
    {
        char op;
        int x,y;
        cin>>op;
        scanf("%d",&x);
        if(op=='M')
        {
            scanf("%d",&y);
            if(del[x]||del[y]||find(x)==find(y))
            {
                continue;
            }
            int u=root[find(x)],v=root[find(y)];
            fa[find(x)]=find(y);
            root[find(x)]=merge(u,v);
        }
        else
        {
            if(del[x])
            {
                printf("0\n");
                continue;
            }
            printf("%d\n",a[root[find(x)]].val);
            del[root[find(x)]]=true;
            root[find(x)]=merge(a[root[find(x)]].lson,a[root[find(x)]].rson);
        }
    }
    return 0;
}
